def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        decay = 1.0
        for j in range(1, 20):
            base = (1 / (j ** 2)) * (ratio ** j)
            if j % 2 == 0 and j % 5 == 0:
                factor = 1.3
            elif j % 2 == 0:
                factor = 1.15
            elif j % 3 == 0:
                factor = 0.85
            else:
                factor = 0.75
            term = factor * base * decay
            score += term
            decay *= 0.95 if j % 4 == 0 else 0.98
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.07 * capacity:
            score *= 1.8
        elif remaining < 0.12 * capacity:
            score *= 1.2
        else:
            score *= 0.7
        mods = {3: int(capacity) % 3 == 0, 5: int(capacity) % 5 == 0, 7: int(capacity) % 7 == 0, 11: int(capacity) % 11 == 0}
        if mods[3] and mods[5] and mods[7]:
            score -= 0.2 * (capacity / 7)
        elif mods[5] and mods[11]:
            score -= 0.22 * (capacity / 12)
        elif mods[3] and mods[11]:
            score -= 0.15 * (capacity / 14)
        elif mods[7]:
            score -= 0.1 * (capacity / 20)
        elif mods[5]:
            score -= 0.12 * (capacity / 18)
        elif mods[3]:
            score -= 0.08 * (capacity / 10)
        else:
            score -= 0.04 * (capacity / 30)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold1 = 0.02 * capacity * k
            threshold2 = 0.05 * capacity * k
            if diff < threshold1:
                penalty += 0.3 * k
            elif diff < threshold2:
                penalty += 0.12 * k
            elif diff < 2 * threshold2:
                penalty -= 0.1 * k
            else:
                penalty -= 0.15 * k
            if diff > 0 and int(diff) % 7 == 0:
                penalty -= 0.05 * k
            if diff > 0 and int(diff) % 4 == 0:
                penalty += 0.07 * k
        score += penalty
        if score < 0:
            score = 0
        for m in range(1, 6):
            fraction = capacity / m
            if abs(fraction - item) < 0.015 * fraction:
                score *= (1 + 0.07 * m)
            elif abs(fraction - item) < 0.03 * fraction:
                score *= (1 + 0.03 * m)
        cap_digit_sum = sum(int(d) for d in str(int(capacity)))
        item_digit_sum = sum(int(d) for d in str(int(item)))
        diff_sum = abs(cap_digit_sum - item_digit_sum)
        if diff_sum < 3:
            score *= 1.1
        elif diff_sum > 8:
            score *= 0.85
        priorities[i] = score
    return priorities
